mapper.sql:
from app.advisor_product p inner join app.sys_user u on u.id = p.creator_id left join ( select n1.product_id, n1.nav, n1.cum_return from app.advisor_product_nav n1 inner join ( select product_id, max(nav_date) as max_nav_date from app.advisor_product_nav group by product_id ) latest on latest.product_id = n1.product_id and latest.max_nav_date = n1.nav_date ) nav on nav.product_id = p.id where p.status = 'PUBLISHED' and p.published_version_no is not null
and ( p.name like concat('%', #{keyword}, '%') or p.strategy_code like concat('%', #{keyword}, '%') )
and p.type = #{type}
and p.risk_level = #{riskLevel}
and p.creator_id = #{creatorId}
and p.id in ( select distinct pc.product_id from app.advisor_product_version v inner join app.advisor_product_component pc on pc.product_version_id = v.id inner join app.fund_info f on f.fund_code = pc.fund_code where v.product_id = p.id and f.company_name like concat('%', #{fundCompany}, '%') )

mapper.select:
select count(1) from app.advisor_product p where p.status = 'PUBLISHED' and p.published_version_no is not null
and ( p.name like concat('%', #{keyword}, '%') or p.strategy_code like concat('%', #{keyword}, '%') )
and p.type = #{type}
and p.risk_level = #{riskLevel}
and p.creator_id = #{creatorId}
and p.id in ( select distinct pc.product_id from app.advisor_product_version v inner join app.advisor_product_component pc on pc.product_version_id = v.id inner join app.fund_info f on f.fund_code = pc.fund_code where v.product_id = p.id and f.company_name like concat('%', #{fundCompany}, '%') )
